r = redis.Redis(host='localhost', port=6379, db=0)


def cache_result(max_age=300):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_id = str(args) + str(kwargs)
            if r.exists(cache_id):
                return r.get(cache_id).decode('utf-8')
            result = func(*args, **kwargs)
            r.setex(cache_id, max_age, str(result))
            return result
        return wrapper
    return decorator


